{
  "storyboardBeats": [
    {
      "id": "beat-01",
      "title": "The score behind the song",
      "narration": "Your music app just played you a song you love, by a band you have never heard of. Two descriptions got compared in a data center and the verdict was: same taste. But sit with what that comparison has to do. A song is not one number. It is loud, fast, sad, bright, many qualities at once, and your taste is that same tangle. So try it first. How would you boil the match between two many-featured things down to a single number? Harder than it sounds. One answer to it runs half of modern machine learning.",
      "visual": "[visual: connect-to-reality] Two tall stacks of qualities slide in side by side, one for the listener's taste and one for the song, each row a named feature in periwinkle: loud, fast, sad, bright, and more trailing off the frame. A single lilac match readout waits with a question mark where its number should be. The question card holds over the unfilled readout, half the frame deliberately empty so the puzzle, not an answer, owns the screen.",
      "tracks": [
        "video",
        "page"
      ],
      "newIdea": "Collapsing two many-featured things into a single match number is a genuine puzzle, and it is what recommendation runs on.",
      "novelElements": [
        "the two many-featured descriptions",
        "the single match readout"
      ],
      "onScreenText": [
        "How would you score the match?"
      ],
      "colors": {
        "lists": "data.observed",
        "score": "data.params",
        "background": "bg",
        "labels": "text"
      },
      "majorReveal": false,
      "misconceptionBeat": false,
      "estimatedSeconds": 34
    },
    {
      "id": "beat-02",
      "title": "Turn the probe and feel it",
      "narration": "You just tried to score that match by hand, and it fought back: too many qualities, no clean way to fold them into one number. Here is the move that lands it. A taste is an arrow: each direction is one quality, and the length is how hard the song leans that way. Take one probe arrow and four candidate arrows. Multiply them entry by entry and add. That single sum is the score, the whole tangle collapsed to one number. Before you touch the probe, call your shot: name the one candidate whose bar will top out. Now turn the probe and watch the bars answer. Point at a candidate and its score climbs. Turn away and it dies. So a big score means two songs are the same, right? Watch again. Stretch one candidate longer without turning it at all, and its bar climbs anyway, on length alone, even though its direction never got closer. Length cheats the meter. The score reads agreement of direction, not sameness, and a long arrow can fake a high number.",
      "visual": "[visual: covary | dynamic-concept] The stacked lists of qualities from the hook fold down, each feature becoming one direction, until each song is a single arrow. All arrows use thin exact strokes with arrowheads sized in proportion to shaft length; the amber probe's head is drawn to the same proportion as the candidates', never bloated or malformed. One amber probe arrow sweeps through directions; four periwinkle candidate arrows hold still; under each candidate a lilac score bar with a small mono numeric readout climbs and dies as the probe turns toward and away from it. Each candidate label, and the 'probe' label, sits nudged clear of every arrow so nothing ever collides, staying readable at every probe angle including when the probe passes candidate B. Candidate c1 carries a length handle: dragging it stretches c1 while its direction holds, and c1's score climbs on length alone. A freeze frame before the sweep carries the prediction card that asks the learner to name the candidate whose bar will top out; after the sweep the probe parks and the four scores land as integers on the bars.",
      "tracks": [
        "video",
        "page"
      ],
      "newIdea": "Multiply pairwise and add: the score climbs with the probe's direction, so agreement is not identity, and stretching a candidate climbs the score on length alone, so size can fake it.",
      "novelElements": [
        "the probe arrow",
        "the candidate arrows",
        "the score bars",
        "the candidate length handle"
      ],
      "onScreenText": [
        "probe",
        "candidates",
        "3  2  0  -2"
      ],
      "colors": {
        "probe": "data.heat",
        "candidates": "data.observed",
        "scores": "data.params",
        "background": "bg",
        "labels": "text"
      },
      "interactiveSpec": "page/interactives/dot-alignment.yaml",
      "predictionPrompt": {
        "prompt": "Before you touch the probe, call your shot: name the one candidate whose bar tops out.",
        "expectedWrongAnswer": "The longest candidate, or the one that looks most similar, tops out, and no score can go negative because similarity cannot drop below zero."
      },
      "majorReveal": false,
      "misconceptionBeat": true,
      "misconception": "similarity-means-identical",
      "estimatedSeconds": 66
    }
  ],
  "scriptSections": [
    {
      "id": "beat-01",
      "title": "The score behind the song",
      "body": "[visual: connect-to-reality] Two tall stacks of qualities slide in side by side, one for the listener's taste and one for the song, each row a named feature in periwinkle: loud, fast, sad, bright, and more trailing off the frame. A single lilac match readout waits with a question mark where its number should be. The question card holds over the unfilled readout, half the frame deliberately empty so the puzzle, not an answer, owns the screen.\n\nYour music app just played you a song you love, by a band you have never heard of. Two descriptions got compared in a data center and the verdict was: same taste. But sit with what that comparison has to do. A song is not one number. It is loud, fast, sad, bright, many qualities at once, and your taste is that same tangle. So try it first. How would you boil the match between two many-featured things down to a single number? Harder than it sounds. One answer to it runs half of modern machine learning."
    },
    {
      "id": "beat-02",
      "title": "Turn the probe and feel it",
      "body": "[visual: covary | dynamic-concept] The stacked lists of qualities from the hook fold down, each feature becoming one direction, until each song is a single arrow. All arrows use thin exact strokes with arrowheads sized in proportion to shaft length; the amber probe's head is drawn to the same proportion as the candidates', never bloated or malformed. One amber probe arrow sweeps through directions; four periwinkle candidate arrows hold still; under each candidate a lilac score bar with a small mono numeric readout climbs and dies as the probe turns toward and away from it. Candidate c1 carries a length handle: dragging it stretches c1 while its direction holds, and c1's score climbs on length alone. A freeze frame before the sweep carries the prediction card.\n\nYou just tried to score that match by hand, and it fought back: too many qualities, no clean way to fold them into one number. Here is the move that lands it. A taste is an arrow: each direction is one quality, and the length is how hard the song leans that way. Take one probe arrow and four candidate arrows. Multiply them entry by entry and add. That single sum is the score, the whole tangle collapsed to one number. Before you touch the probe, call your shot: name the one candidate whose bar will top out. Now turn the probe and watch the bars answer. Point at a candidate and its score climbs. Turn away and it dies. So a big score means two songs are the same, right? Watch again. Stretch one candidate longer without turning it at all, and its bar climbs anyway, on length alone, even though its direction never got closer. Length cheats the meter. The score reads agreement of direction, not sameness, and a long arrow can fake a high number."
    }
  ],
  "fileEdits": [
    {
      "path": "spine.md",
      "find": "| beat-01 | Hook | The recommendation moment: two lists of numbers agreed; how do you score a match? | 24 |",
      "replace": "| beat-01 | Hook | The recommendation moment: two many-featured songs matched; pose collapsing many features into one number as a puzzle the reader tries | 34 |"
    },
    {
      "path": "spine.md",
      "find": "| beat-02 | Felt elemental unit | Multiply pairwise and add; the learner sweeps the probe and feels the score move; misconception (similarity means identical) voiced and refuted | 34 |",
      "replace": "| beat-02 | Felt elemental unit | The reader attempts, then multiply pairwise and add arrives as the resolution; the learner sweeps the probe and feels the score move; misconception (similarity means identical) voiced and refuted | 66 |"
    },
    {
      "path": "spine.md",
      "find": "Total 112s estimated; hard cap 540s (L10).",
      "replace": "Total 154s estimated; hard cap 540s (L10)."
    }
  ],
  "summary": "Reframed beat-01 to pose comparing many-featured things as a puzzle the reader attempts, and beat-02 so multiply-and-add arrives as the earned resolution; spine beat table and totals updated to match."
}

